#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin

# Test: verify-streak/1.0 ledger contract + streak_target schema slot (#2557)
#
# The streak gate (src/skills/verify/references/streak-gate.md) is an
# LLM-executed protocol, so its ledger contract lives as a documented JSON
# example, not runtime-validated code. This lint keeps that contract from
# silently drifting:
#   - the streak-gate.md ledger example parses and carries every
#     verify-streak/1.0 field, including the last_run_ts freshness stamp
#   - the reset rule (any non-READY-FOR-MERGE zeroes the count) stays documented
#   - the streak_target slot exists in the shared rubric schema as an
#     integer >= 2, so a configured target is validated not ignored
#   - if verify/rubric.json sets streak_target, it satisfies that slot
# No new deps — plain node -e + awk.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
GATE_DOC="$REPO_ROOT/src/skills/verify/references/streak-gate.md"
SCHEMA="$REPO_ROOT/src/skills/shared/rubric.schema.json"
VERIFY_RUBRIC="$REPO_ROOT/src/skills/verify/rubric.json"
ERR="$(mktemp)"
trap 'rm -f "$ERR"' EXIT

FAILED=0
pass() { echo "  PASS $1"; }
fail() { echo "  FAIL $1"; FAILED=$((FAILED + 1)); }

# 1. Gate doc + schema exist.
[[ -f "$GATE_DOC" ]] || { echo "FAIL: missing $GATE_DOC"; exit 1; }
[[ -f "$SCHEMA" ]] || { echo "FAIL: missing $SCHEMA"; exit 1; }

# 2. Extract the first fenced JSON block (the ledger example) and assert it
#    carries every required verify-streak/1.0 field. Extraction is best-effort;
#    an empty result fails the contract check below with a clear message.
LEDGER_JSON="$(awk '/```json/{f=1;next} /```/{if(f)exit} f' "$GATE_DOC")"  # silent: best-effort

if node -e '
  const j = JSON.parse(process.argv[1]);
  const req = ["schema","scope","target","current","met","reset_count","last_run_ts","history"];
  const missing = req.filter(k => !(k in j));
  if (j.schema !== "verify-streak/1.0") { console.error("schema field != verify-streak/1.0"); process.exit(1); }
  if (missing.length) { console.error("missing fields: " + missing.join(",")); process.exit(1); }
' "$LEDGER_JSON" 2>"$ERR"; then
  pass "ledger example carries all verify-streak/1.0 fields (incl. last_run_ts)"
else
  fail "ledger contract drift: $(cat "$ERR")"
fi

# 3. Reset rule stays documented.
if grep -qiE 'any non-.?READY|ANY non-ready|One red zeroes' "$GATE_DOC"; then
  pass "reset rule documented (any non-READY zeroes the count)"
else
  fail "reset rule text not found in streak-gate.md"
fi

# 4. streak_target slot in the shared rubric schema: integer, minimum 2.
if node -e '
  const s = JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"));
  const slot = s.properties && s.properties.streak_target;
  if (!slot) { console.error("no streak_target property"); process.exit(1); }
  if (slot.type !== "integer") { console.error("streak_target not integer"); process.exit(1); }
  if (slot.minimum !== 2) { console.error("streak_target minimum != 2"); process.exit(1); }
' "$SCHEMA" 2>"$ERR"; then
  pass "rubric schema exposes validated streak_target slot (integer >= 2)"
else
  fail "streak_target slot invalid/missing: $(cat "$ERR")"
fi

# 5. If verify/rubric.json sets streak_target, it must satisfy the slot.
if [[ -f "$VERIFY_RUBRIC" ]]; then
  if node -e '
    const r = JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"));
    if ("streak_target" in r) {
      if (!Number.isInteger(r.streak_target) || r.streak_target < 2) {
        console.error("streak_target=" + r.streak_target + " violates slot"); process.exit(1);
      }
    }
  ' "$VERIFY_RUBRIC" 2>"$ERR"; then
    pass "verify/rubric.json streak_target (if set) satisfies the slot"
  else
    fail "verify/rubric.json streak_target invalid: $(cat "$ERR")"
  fi
fi

echo ""
if [[ "$FAILED" -eq 0 ]]; then
  echo "SUCCESS: streak-gate contract intact"
  exit 0
else
  echo "FAILED: $FAILED streak-gate contract check(s)"
  exit 1
fi
